import{_ as s,c as a,o as i,aj as t}from"./chunks/framework.BlveriQe.js";const k=JSON.parse('{"title":"App Secrets","description":"","frontmatter":{},"headers":[],"relativePath":"getting-started/app-secrets.md","filePath":"getting-started/app-secrets.md"}'),n={name:"getting-started/app-secrets.md"};function r(l,e,o,h,p,d){return i(),a("div",null,[...e[0]||(e[0]=[t(`<h1 id="app-secrets" tabindex="-1">App Secrets <a class="header-anchor" href="#app-secrets" aria-label="Permalink to “App Secrets”">​</a></h1><p>Your app&#39;s server-side configuration needs credentials — API keys for LLM providers, tokens for external services, signing secrets. <strong>App secrets</strong> are the platform&#39;s server-side store for them: set a value once with the CLI, reference it from server-side config as <span><code>{{secrets.KEY}}</code></span>, and the value resolves on the server. Secrets never appear in your repo, your client code, or anything shipped to users.</p><h2 id="managing-secrets" tabindex="-1">Managing Secrets <a class="header-anchor" href="#managing-secrets" aria-label="Permalink to “Managing Secrets”">​</a></h2><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Create or update a secret</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">primitive</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> secrets</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> OPENAI_API_KEY</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --value</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sk-...</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --summary</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;OpenAI production key&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># List secrets (values are never shown)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">primitive</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> secrets</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Delete a secret</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">primitive</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> secrets</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> delete</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> OPENAI_API_KEY</span></span></code></pre></div><p>Secrets are write-only: once set, a value can be overwritten or deleted but never read back — <code>list</code> shows keys and summaries only. Use <code>--summary</code> so you can tell keys apart later.</p><p>Secrets are scoped to an app, so each of your <a href="./primitive-cli.html#named-environments">environments</a> (dev, staging, production) keeps its own values — set the production key with <code>--env prod</code> and the development key with <code>--env dev</code>.</p><h2 id="referencing-secrets" tabindex="-1">Referencing Secrets <a class="header-anchor" href="#referencing-secrets" aria-label="Permalink to “Referencing Secrets”">​</a></h2><p>Server-side config refers to a secret as <span><code>{{secrets.KEY}}</code></span>, resolved at the moment the config runs:</p><table tabindex="0"><thead><tr><th>Surface</th><th>Where secrets resolve</th></tr></thead><tbody><tr><td><a href="./api-integrations.html">API Integrations</a></td><td><code>requestConfig.defaultHeaders</code> and <code>requestConfig.staticQuery</code> — resolved when the request is proxied</td></tr><tr><td><a href="./workflows.html">Workflows</a></td><td>Step config templates and CEL expressions (<code>runIf</code>), via the <code>secrets.*</code> context variable</td></tr><tr><td><a href="./workflows.html#via-inbound-webhooks">Inbound webhooks</a></td><td>A webhook&#39;s <code>signingSecret</code> — resolved server-side when an incoming event is verified</td></tr><tr><td><a href="./working-with-databases.html">Databases</a></td><td>CEL access expressions on operations and trigger stamp values can read <code>secrets.*</code></td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">The CEL <code>secrets.*</code> variable is declared-only</p><p>The <span><code>{{secrets.KEY}}</code></span> template form (integration headers, webhook <code>signingSecret</code>, step-config templates) resolves any secret you have set. The <code>secrets.*</code> variable <strong>in a CEL expression</strong> — a workflow <code>runIf</code>, a database operation&#39;s access rule, or a trigger&#39;s stamp value — binds only the secrets that config <strong>declares</strong>. List them in the owning config&#39;s TOML (a database or collection type config, or a workflow definition):</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">secrets = [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;STRIPE_KEY&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p>An undeclared <code>secrets.KEY</code> is absent when the rule evaluates, so a rule that reads it denies. Declare every secret a CEL rule needs.</p></div><p>For example, an integration authenticates with a header that names the secret:</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># config/integrations/openai.toml</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">requestConfig</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">defaultHeaders</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">Authorization = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;Bearer {{secrets.OPENAI_API_KEY}}&quot;</span></span></code></pre></div><h2 id="keep-secrets-server-side" tabindex="-1">Keep Secrets Server-Side <a class="header-anchor" href="#keep-secrets-server-side" aria-label="Permalink to “Keep Secrets Server-Side”">​</a></h2><p>The point of the store is that secret values only ever exist where the server resolves them:</p><ul><li><strong>Never inline credentials in TOML</strong> — config files are committed to your repo. Reference <span><code>{{secrets.KEY}}</code></span> instead.</li><li><strong>Keep credentials in integration config, not workflow steps</strong> — a workflow step&#39;s resolved config is recorded on the run, so a secret passed through <code>request.headers</code> would appear in step output snapshots. Resolution inside the integration&#39;s <code>defaultHeaders</code> happens after that snapshot, where it stays invisible. See <a href="./workflows.html#integration-call"><code>integration.call</code></a>.</li><li><strong>Clients can&#39;t read secrets</strong> — there is no client API for secret values; apps only ever see the results of server-side calls that used them.</li></ul><h2 id="config-vars" tabindex="-1">Config Vars <a class="header-anchor" href="#config-vars" aria-label="Permalink to “Config Vars”">​</a></h2><p>Not every server-side value is a credential. <strong>Config vars</strong> are the non-secret twin of app secrets: the same key format, the same per-app limit, and the same declare-and-bind path into CEL rules — but the values are plaintext. Use a var for something like a platform-assigned group ID that a rule needs to compare against; use a secret for anything that grants access to an external system.</p><div class="language-bash"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Create or update a var</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">primitive</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vars</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> set</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ADMIN_GROUP_ID</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --value</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> grp_01ABC</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --summary</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Admins group id&quot;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># List vars (values are shown — vars are not secret)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">primitive</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vars</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> list</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Delete a var</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">primitive</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vars</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> delete</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ADMIN_GROUP_ID</span></span></code></pre></div><p>Unlike secrets, vars are readable: <code>list</code> shows every value, and a var may appear unmasked in debug traces. Never store a credential in a var. Vars (like secrets) can also be managed from the <a href="./admin-console.html">Admin Console</a>, where their values display in plain text.</p><div class="warning custom-block"><p class="custom-block-title">The CEL <code>vars.*</code> variable is declared-only</p><p>A CEL rule reads a var as <code>vars.&lt;KEY&gt;</code>, bound only to the keys the owning config <strong>declares</strong> — the same declared-only discipline as <code>secrets.*</code>. List them in the owning config&#39;s TOML alongside any declared secrets:</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">vars = [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;ADMIN_GROUP_ID&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p>An undeclared <code>vars.KEY</code> is absent when the rule evaluates, so a rule that reads it denies.</p></div><p>A rule then reads the declared var like any other CEL variable:</p><div class="language-toml"><button title="Copy Code" class="copy"></button><span class="lang">toml</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">access = </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;isMemberOf(&#39;team&#39;, vars.ADMIN_GROUP_ID)&quot;</span></span></code></pre></div><h2 id="next-steps" tabindex="-1">Next Steps <a class="header-anchor" href="#next-steps" aria-label="Permalink to “Next Steps”">​</a></h2><ul><li><strong><a href="./api-integrations.html">API Integrations</a></strong> — The most common secret consumer: authenticated calls to external APIs</li><li><strong><a href="./workflows.html">Workflows</a></strong> — Reference secrets from step templates</li><li><strong><a href="./configuring-primitive-services.html">Configuring Primitive Services</a></strong> — The sync loop your secret-referencing config travels through</li></ul>`,24)])])}const g=s(n,[["render",r]]);export{k as __pageData,g as default};
